int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, m;
    std::cin >> n >> m;
    std::vector<int> s(n), t(m);
    bool has[2] = {false, false};
    for (int i = 0; i < n; ++i) { std::cin >> s[i]; has[s[i]] = true; }
    for (int i = 0; i < m; ++i) std::cin >> t[i];
    for (int x : t) {
        if (!has[x]) { std::cout << -1 << '\n'; return 0; }
    }

    long long ans = m;
    if (s[0] != t[0]) {
        int best = n;
        for (int i = 0; i < n; ++i) {
            if (s[i] == t[0]) best = std::min(best, std::min(i, n - i));
        }
        ans += best;
    }
    for (int i = 1; i < m; ++i) {
        if (t[i] != t[i - 1]) ++ans;
    }
    std::cout << ans << '\n';
