int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int T;
    std::cin >> T;
    while (T--) {
        long long n2, n3, n4;
        std::cin >> n2 >> n3 >> n4;
        long long p3 = n3 / 2;
        long long ans = 0;
        long long x = std::min(p3, n4);          // 3+3+4
        ans += x; p3 -= x; n4 -= x;
        x = std::min(p3, n2 / 2);               // 3+3+2+2
        ans += x; p3 -= x; n2 -= 2 * x;
        x = std::min(n4 / 2, n2);               // 4+4+2
        ans += x; n4 -= 2 * x; n2 -= x;
        x = std::min(n4, n2 / 3);               // 4+2+2+2
        ans += x; n4 -= x; n2 -= 3 * x;
        ans += n2 / 5;                          // 2*5
        std::cout << ans << '\n';
    }
    return 0;
}

