struct Query { int t, n, c; };

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long h, w;
    int c, q;
    std::cin >> h >> w >> c >> q;
    std::vector<Query> qs(q);
    for (auto& e : qs) std::cin >> e.t >> e.n >> e.c;
    std::vector<int> row(h + 1, 0), col(w + 1, 0);
    std::vector<long long> ans(c + 1, 0);
    long long usedR = 0, usedC = 0;
    for (int i = q - 1; i >= 0; --i) {
        if (qs[i].t == 1) {
            if (!row[qs[i].n]) {
                row[qs[i].n] = 1; ++usedR;
                ans[qs[i].c] += w - usedC;
            }
        } else {
            if (!col[qs[i].n]) {
                col[qs[i].n] = 1; ++usedC;
                ans[qs[i].c] += h - usedR;
            }
        }
    }
    for (int i = 1; i <= c; ++i) {
        if (i > 1) std::cout << ' ';
        std::cout << ans[i];
    }
    std::cout << '\n';
    return 0;
}

