#include <iostream>
#include <map>

const long long MOD = 998244353LL;
std::map<long long, long long> memo;

long long solve(long long x) {
    if (x <= 4) return x;
    auto it = memo.find(x);
    if (it != memo.end()) return it->second;
    long long a = solve(x / 2);
    long long b = solve((x + 1) / 2);
    return memo[x] = a * b % MOD;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long x;
    std::cin >> x;
    std::cout << solve(x) << '\n';
    return 0;
}

