#include <iostream>

long long revnum(long long x) {
    long long r = 0;
    while (x > 0) {
        r = r * 10 + x % 10;
        x /= 10;
    }
    return r;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    long long n, k;
    std::cin >> n >> k;
    long long r = revnum(k);
    if (r < k) {
        std::cout << 0 << '\n';
        return 0;
    }
    long long ans = 0;
    for (long long x = k; x <= n; x *= 10) ++ans;
    if (r != k) {
        for (long long x = r; x <= n; x *= 10) ++ans;
    }
    std::cout << ans << '\n';
    return 0;
}

