int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::string s, t;
    std::cin >> n >> s >> t;
    int diff = 0;
    for (int i = 0; i < n; ++i) if (s[i] != t[i]) ++diff;
    if (diff % 2) {
        std::cout << -1 << '\n';
        return 0;
    }
    int needS = diff / 2, needT = diff / 2;
    int rem = diff;
    std::string u(n, '0');
    for (int i = 0; i < n; ++i) {
        if (s[i] == t[i]) { u[i] = '0'; continue; }
        --rem;
        bool zeroMeansT = (t[i] == '0');
        if (zeroMeansT) {
            if (needT > 0 && needS <= rem) { u[i] = '0'; --needT; }
            else { u[i] = '1'; --needS; }
        } else {
            if (needS > 0 && needT <= rem) { u[i] = '0'; --needS; }
            else { u[i] = '1'; --needT; }
        }
    }
    std::cout << u << '\n';
    return 0;
}

