#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    long long k;
    std::cin >> n >> k;
    const int INF = 1 << 28;
    std::vector<std::vector<int>> edge(n, std::vector<int>(n));
    std::vector<std::vector<int>> dist(n, std::vector<int>(n, INF));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> edge[i][j];
            if (edge[i][j]) dist[i][j] = 1;
        }
        dist[i][i] = 0;
    }
    for (int mid = 0; mid < n; ++mid) {
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                dist[i][j] = std::min(dist[i][j], dist[i][mid] + dist[mid][j]);
            }
        }
    }
    std::vector<int> cycle(n, INF);
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (edge[i][j] && dist[j][i] < INF) cycle[i] = std::min(cycle[i], 1 + dist[j][i]);
        }
    }

    int q;
    std::cin >> q;
    while (q--) {
        long long s, t;
        std::cin >> s >> t;
        int a = static_cast<int>((s - 1) % n);
        int b = static_cast<int>((t - 1) % n);
        int ans = (a == b ? cycle[a] : dist[a][b]);
        std::cout << (ans >= INF ? -1 : ans) << '\n';
    }
    return 0;
}

