int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<long long> a(n), b(n);
    for (long long& x : a) std::cin >> x;
    std::sort(a.begin(), a.end());
    int small = 0, large = (n + 1) / 2;
    for (int i = 0; i < n; ++i) {
        if (i % 2 == 1) b[i] = a[large++];
        else b[i] = a[small++];
    }
    bool ok = true;
    for (int i = 1; i + 1 < n; i += 2) {
        if (!(b[i - 1] < b[i] && b[i] > b[i + 1])) ok = false;
    }
    std::cout << (ok ? "Yes" : "No") << '\n';
    return 0;
}
